//###########################################################################

//Script code

//###########################################################################





OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page

   if(IsProject()==0)   

   {

//      int textMode=0;

      CString parentWnd;

   }

   int textMode=0;

   parentWnd.SetString("wszyscy.bdf");



   int left=0;

   int right=0;



   LoadGroup("Cursors.grp");

   SetCursor(0);



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   int puzzleNo=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

//############################################################################



   Sound_Holder.PlayDSound(1);

   SetTextMode();

   FadeScreen(1,1000);

//   SetTimer(5000);

}





void OnClosePage(void)

{

	// Add your close page handler code here



}



void SetTextMode(void)

{

   if(textMode)

   {

      playStatus = 1;

      Sound_Holder.SetPlayDSoundParameters(1,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

   else

   {

      playStatus = 0;

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(1,0,0,0);

   }

}



void HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(textMode)   return;

   switch(rectID)

   {

      case 0:

      case 3:

      case 4:

      case 5:

         Transparent_Video_Holder.Play(rectID,0);

         break;

      case 1:

         if(left)

         {

            Transparent_Video_Holder.Play(2,0);

            left=0;

         }

         else

         {

            Transparent_Video_Holder.Play(1,0);

            left=1;

         }

         break;

      case 6:

         if(right)

         {

            Transparent_Video_Holder.Play(6,0);

            right=0;

         }

         else

         {

            Transparent_Video_Holder.Play(7,0);

            right=1;

         }

         break;

      case 10:

         FadeScreen(0,1000);

         LoadPage("krawiec.bdf");

         break;

      case 11:

         FadeScreen(0,1000);

         LoadPage("murarz.bdf");

         break;

      case 12:

         FadeScreen(0,1000);

         LoadPage("szewc.bdf");

         break;

   }

}





void HotSpot_Holder.MouseMoveIn(int videoID)

{

   if(textMode==0)   SetCursor(1);

}





void HotSpot_Holder.MouseMoveOut(int videoID)

{

   SetCursor(0);

}





void Transparent_Video_Holder.TheEnd(int videoID)

{

   if(videoID==0)

   {

      FadeScreen(0,1000);

      LoadPage("Piekarz.bdf");

   }

}





//############################################################# T O O L B A R #######

//#############################################################---------------#######

void Group.HotSpot_Holder.MouseMoveIn(int rectID)

{

   switch(rectID)

   {

      case 0:

         Group.HotSpot_Holder.DisableHotSpot(0);

         Group.Sprite_Holder.DisableTimers();



         Group.Sprite_Holder.GotoXY(0,480,0);

         Group.Sprite_Holder.GotoXY(2,544,14);

         Group.Sprite_Holder.GotoXY(3,584,14);

         Group.Sprite_Holder.GotoXY(4,515,84);

         Group.Sprite_Holder.GotoXY(5,559,210);

         Group.Sprite_Holder.GotoXY(6,558,282);

         Group.Sprite_Holder.GotoXY(7,557,404);



         Group.Sprite_Holder.SynchronizeTimers();

         Group.Sprite_Holder.EnableTimers();

         Group.Sound_Holder.PlayDSound(0);

         break;

      case 1:

         if(toolbar)

         {

            Group.Sprite_Holder.DisableTimers();

            Group.Sprite_Holder.GotoXY(0,640,0);

            Group.Sprite_Holder.GotoXY(7,717,404);



            switch(toolbarPhase)

            {

               case 0:

                  Group.Sprite_Holder.GotoXY(2,704,14);

                  Group.Sprite_Holder.GotoXY(3,744,14);

                  Group.Sprite_Holder.GotoXY(4,675,84);

                  Group.Sprite_Holder.GotoXY(5,719,210);

                  Group.Sprite_Holder.GotoXY(6,718,282);

                  break;

               case 1:

                  Sprite_Holder.GotoXY(0,713,8);

                  Sprite_Holder.GotoXY(1,701,64);

                  Sprite_Holder.GotoXY(2,718,135);

                  Sprite_Holder.GotoXY(3,709,204);

                  Sprite_Holder.GotoXY(4,714,265);

                  break;

               case 2:

                  Group.Sprite_Holder.GotoXY(8,693,22);

                  Group.Sprite_Holder.GotoXY(9,708,156);

                  break;

            }

            Group.Sprite_Holder.SynchronizeTimers();

            Group.Sprite_Holder.EnableTimers();

            Group.Sound_Holder.PlayDSound(0);

            toolbar=0;

            toolbarPhase=0;

         }

         else

         {

            Group.Sprite_Holder.GotoXY(11,-56,-70);

            SetCursor(0);

         }

         txtHotSpotOn=0;

         Group.HotSpot_Holder.DisableHotSpot(1);

         Group.HotSpot_Holder.EnableHotSpot(0);

         toolbarCase=0;

         break;

      case 2:

         if(txtHotSpotOn==0)   

         {

            Group.Sound_Holder.PlayDSound(3);	

            Group.Sprite_Holder.GotoXY(11,0,0);

         }

         break;

   }

}





void Group.Sprite_Holder.InPlace(int spriteID,int x,int y)

{

   switch(spriteID)

   {

      case 0:

         if(x==480)

         {

            toolbar=1;

            Group.HotSpot_Holder.EnableHotSpot(1);

            SetCursor(1);

         }

         else

         {

            SetCursor(0);

            Group.Sprite_Holder.ChangePhase(2,0);

            Group.Sprite_Holder.ChangePhase(3,0);

            Group.Sprite_Holder.ChangePhase(4,0);

            Group.Sprite_Holder.ChangePhase(5,0);

            Group.Sprite_Holder.ChangePhase(6,0);

            Group.Sprite_Holder.ChangePhase(7,0);

            Group.Sprite_Holder.ChangePhase(8,0);

            Group.Sprite_Holder.ChangePhase(9,0);



            switch(toolbarCase)

            {

               case 2:   //lewo   

                  FadeScreen(0,1000);

                  LoadPage("rachunek.bdf");

                  break;

               case 3:   //prawo

                  FadeScreen(0,1000);

                  LoadPage("zosia.bdf");

                  break;

               case 4:   //recytacja

                  FadeScreen(0,1000);

                  LoadPage("wszysc_r.bdf");

                  break;

               case 5:   //roznice

                  FadeScreen(0,1000);

                  LoadPage("wszysc_c.bdf");

                  break;

               case 6:   //puzzle

                  Group.Sprite_Holder.DisableTimers();



                  Group.Sprite_Holder.GotoXY(0,480,0);

                  Sprite_Holder.GotoXY(0,553,8);

                  Sprite_Holder.GotoXY(1,541,64);

                  Sprite_Holder.GotoXY(2,558,135);

                  Sprite_Holder.GotoXY(3,549,204);

                  Sprite_Holder.GotoXY(4,554,265);

                  Group.Sprite_Holder.GotoXY(7,557,404);



                  Group.Sprite_Holder.SynchronizeTimers();

                  Group.Sprite_Holder.EnableTimers();

                  Group.Sound_Holder.PlayDSound(0);

                  toolbarPhase=1;

                  break;

               case 7:   //Plansza wyboru

                  FadeScreen(0,1000);

                  LoadPage("Wyborw.bdf");

                  break;

               case 8:   //puzzle trudne

                  FadeScreen(0,1000);

                  switch(puzzleNo)

                  {

                     case 0:

                        LoadPage("wszyscp1.bdf");

                        break;

                     case 1:

                        LoadPage("murarzp1.bdf");

                        break;

                     case 2:

                        LoadPage("piekarp1.bdf");

                        break;

                     case 3:

                        LoadPage("szewcp1.bdf");

                        break;

                     case 4:

                        LoadPage("krawiep1.bdf");

                        break;

                  }

                  break;

               case 9:   //puzzle latwe

                  FadeScreen(0,1000);

                  switch(puzzleNo)

                  {

                     case 0:

                        LoadPage("wszyscp2.bdf");

                        break;

                     case 1:

                        LoadPage("murarzp2.bdf");

                        break;

                     case 2:

                        LoadPage("piekarp2.bdf");

                        break;

                     case 3:

                        LoadPage("szewcp2.bdf");

                        break;

                     case 4:

                        LoadPage("krawiep2.bdf");

                        break;

                  }

                  break;

               case 12:

               case 13:

               case 14:

               case 15:

               case 16:

                  Sprite_Holder.ChangePhase(0,0);

                  Sprite_Holder.ChangePhase(1,0);

                  Sprite_Holder.ChangePhase(2,0);

                  Sprite_Holder.ChangePhase(3,0);

                  Sprite_Holder.ChangePhase(4,0);



                  Group.Sprite_Holder.DisableTimers();



                  Group.Sprite_Holder.GotoXY(0,480,0);



                  Group.Sprite_Holder.GotoXY(8,533,22);

                  Group.Sprite_Holder.GotoXY(9,548,156);

                  Group.Sprite_Holder.GotoXY(7,557,404);



                  Group.Sprite_Holder.SynchronizeTimers();

                  Group.Sprite_Holder.EnableTimers();

                  Group.Sound_Holder.PlayDSound(0);

                  toolbarPhase=2;

                  break;

            }

         }

         break;

      case 11:

         if(x==0)

         {

            Group.HotSpot_Holder.EnableHotSpot(1);

            txtHotSpotOn=1;

            SetCursor(1);

         }

         break;

   }

}



void Group.Sprite_Holder.MouseMoveIn(int spriteID)

{

   if(spriteID && toolbar)

      SetCursor(1);

}



void Group.Sprite_Holder.MouseMoveOut(int spriteID)

{

   if(spriteID)

      SetCursor(0);

}



void Group.Sprite_Holder.MouseClickOnDown(int spriteID)

{

   if(spriteID==0)   return;

   if(spriteID==11)

   {

      Group.Sprite_Holder.GotoXY(11,-56,-70);

      Group.Sound_Holder.PlayDSound(2);	

      toolbarCase=spriteID;

      SetCursor(0);

      if(textMode)    textMode=0;

      else            textMode=1;

      SetTextMode();

   }

   else

   {

      Group.HotSpot_Holder.DisableHotSpot(1);

      Group.Sprite_Holder.ChangePhase(spriteID,1);

      switch(spriteID)	

      {

         case 2:   //lewo

         case 3:   //prawo 

            Group.Sound_Holder.PlayDSound(4);

            break;

         case 4:   //recytacja

            Group.Sound_Holder.PlayDSound(5);

            break;

         case 5:   //roznice

            Group.Sound_Holder.PlayDSound(6);

            break;

         case 6:   //puzzle

            Group.Sound_Holder.PlayDSound(7);

            break;

         case 7:   //plansza glowna

            Group.Sound_Holder.PlayDSound(8);

            break;

         case 8:   //puzzle latwe

            Group.Sound_Holder.PlayDSound(9);

            break;

         case 9:   //puzzle trudne

            Group.Sound_Holder.PlayDSound(10);

            break;

         case 10:  //parent window

            Group.Sound_Holder.PlayDSound(4);

            break;

      }

   }

}



void Group.Sprite_Holder.MouseClickOnUp(int spriteID)

{

   if(spriteID==0 || spriteID==5 || spriteID==6 || spriteID==8 || spriteID==9 || spriteID==11)   return;

   Group.Sprite_Holder.DisableTimers();



   Group.Sprite_Holder.GotoXY(0,640,0);

   Group.Sprite_Holder.GotoXY(7,717,404);



   switch(toolbarPhase)

   {

      case 0:

         Group.Sprite_Holder.GotoXY(2,704,14);

         Group.Sprite_Holder.GotoXY(3,744,14);

         Group.Sprite_Holder.GotoXY(4,675,84);

         Group.Sprite_Holder.GotoXY(5,719,210);

         Group.Sprite_Holder.GotoXY(6,718,282);

         break;

      case 1:

         Sprite_Holder.GotoXY(0,713,8);

         Sprite_Holder.GotoXY(1,701,64);

         Sprite_Holder.GotoXY(2,718,135);

         Sprite_Holder.GotoXY(3,709,204);

         Sprite_Holder.GotoXY(4,714,265);

         break;

      case 2:

         Group.Sprite_Holder.GotoXY(8,693,22);

         Group.Sprite_Holder.GotoXY(9,708,156);

         toolbarPhase=0;

         break;

   }

   Group.Sprite_Holder.SynchronizeTimers();

   Group.Sprite_Holder.EnableTimers();

   Group.Sound_Holder.PlayDSound(0);

   toolbar=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   toolbarCase=spriteID;

}



void Group.Sprite_Holder.EndAnimation(int spriteID)

{

   if(spriteID!=5 && spriteID!=6 && spriteID!=8 && spriteID!=9)   return;



   Group.Sprite_Holder.ChangePhase(spriteID,2);



   Group.Sprite_Holder.DisableTimers();



   if(toolbarPhase==0)

   {

      Group.Sprite_Holder.GotoXY(0,640,0);

      Group.Sprite_Holder.GotoXY(2,704,14);

      Group.Sprite_Holder.GotoXY(3,744,14);

      Group.Sprite_Holder.GotoXY(4,675,84);

      Group.Sprite_Holder.GotoXY(5,719,210);

      Group.Sprite_Holder.GotoXY(6,718,282);

      Group.Sprite_Holder.GotoXY(7,717,404);

   }

   else

   {

      Group.Sprite_Holder.GotoXY(0,640,0);

      Group.Sprite_Holder.GotoXY(8,693,22);

      Group.Sprite_Holder.GotoXY(9,708,156);

      Group.Sprite_Holder.GotoXY(7,717,404);

      toolbarPhase=0;

   }

   Group.Sprite_Holder.SynchronizeTimers();

   Group.Sprite_Holder.EnableTimers();

   Group.Sound_Holder.PlayDSound(0);

   toolbar=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   toolbarCase=spriteID;

}

//#############################################################

//############################################################# 













void Text_Holder.ScrollTextUp(int textID)

{

   SetCursor(3);

}





void Text_Holder.ScrollTextDown(int textID)

{

   SetCursor(4);

}





void Text_Holder.EndScrollText(int textID)

{

   if(playStatus)  SetCursor(2);

   else            SetCursor(5);

}





void Text_Holder.MouseMoveIn(int textID)

{

   if(playStatus)

      SetCursor(2);

   else

      SetCursor(5);

}





void Text_Holder.MouseMoveOut(int textID)

{

   SetCursor(0);

}





void Text_Holder.ClickOnText(int textID)

{

   if(playStatus)

   {

      playStatus=0;

      Sound_Holder.Stop(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(1,0,0,0);

      SetCursor(5);

   }

   else

   {

      playStatus=1;

      Sound_Holder.SetPlayDSoundParameters(1,-1000,0,0);

      Text_Holder.PlaySynchroText(0);

      SetCursor(2);

   }

}





void Text_Holder.EndOfSynchroText(int textID)

{

   if(playStatus)

      SetCursor(5);

   else

      SetCursor(0);

   playStatus=0;

   Sound_Holder.SetPlayDSoundParameters(1,0,0,0);

}





void Sound_Holder.EndPlaySound(int soundID)

{

   if(soundID==0 && textMode)

   { 

      playStatus=1;

      Text_Holder.EnableMouse(0);

      Text_Holder.PlaySynchroText(0);

   }

}





//######################################################## 

void Sprite_Holder.MouseMoveIn(int spriteID)

{

   SetCursor(1);

}



void Sprite_Holder.MouseMoveOut(int spriteID)

{

   SetCursor(0);

}



void Sprite_Holder.MouseClickOnDown(int spriteID)

{

   Sprite_Holder.ChangePhase(spriteID,1);

   Group.Sound_Holder.PlayDSound(12);



}



void Sprite_Holder.MouseClickOnUp(int spriteID)

{

   Group.Sprite_Holder.DisableTimers();



   Group.Sprite_Holder.GotoXY(0,640,0);



   Sprite_Holder.GotoXY(0,713,8);

   Sprite_Holder.GotoXY(1,701,64);

   Sprite_Holder.GotoXY(2,718,135);

   Sprite_Holder.GotoXY(3,709,204);

   Sprite_Holder.GotoXY(4,714,265);

   Group.Sprite_Holder.GotoXY(7,717,404);



   Group.Sprite_Holder.SynchronizeTimers();

   Group.Sprite_Holder.EnableTimers();

   Group.Sound_Holder.PlayDSound(0);

   toolbar=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   toolbarCase=spriteID+12;

   puzzleNo=spriteID;

}

